#include <cuda_runtime.h>
#include <cstdio>
#include <cstdint>
#include <cstddef>
#include <cstdlib>
#include <algorithm>
#include <cstring>

__global__ void measure_dram_latency(volatile uint32_t* indices, uint64_t* cycles, size_t size) {
    if (threadIdx.x != 0 || blockIdx.x != 0) return;

    uint32_t idx = 0;

    // Compiler barrier before timing
    asm volatile("" : : : "memory");

    volatile uint64_t start = clock64();

    #pragma unroll 1
    for (uint64_t i = 0; i < 10000000; i++) {
        idx = indices[idx];  // Serial dependency chain
    }

    volatile uint64_t end = clock64();

    // Compiler barrier after timing
    asm volatile("" : : : "memory");

    // Anti-optimization sink - cast to 64-bit first
    volatile uint64_t sink64 = (uint64_t)idx;
    asm volatile("" : "+l"(sink64) : : "memory");

    // Average cycles per access
    *cycles = (end - start) / 10000000;
}

// Baseline measurement without memory access
__global__ void measure_baseline(uint64_t* cycles) {
    if (threadIdx.x != 0 || blockIdx.x != 0) return;

    uint32_t dummy = 0;

    // Compiler barrier before timing
    asm volatile("" : : : "memory");

    volatile uint64_t start = clock64();

    #pragma unroll 1
    for (uint64_t i = 0; i < 10000000; i++) {
        dummy = (dummy + 1) & 0xFFFFFFF;
    }

    volatile uint64_t end = clock64();

    // Compiler barrier after timing
    asm volatile("" : : : "memory");

    // Anti-optimization sink
    volatile uint64_t sink64 = (uint64_t)dummy;
    asm volatile("" : "+l"(sink64) : : "memory");

    *cycles = (end - start) / 10000000;
}

int main() {
    const size_t SIZE = 32 * 1024 * 1024; // 32M elements = 128 MB
    const uint64_t ITERATIONS = 10000000;

    // Allocate device memory
    uint32_t* d_indices;
    uint64_t* d_cycles;
    uint64_t* d_baseline;

    cudaMalloc(&d_indices, SIZE * sizeof(uint32_t));
    cudaMalloc(&d_cycles, sizeof(uint64_t));
    cudaMalloc(&d_baseline, sizeof(uint64_t));

    // Allocate host memory for indices
    uint32_t* h_indices = (uint32_t*)malloc(SIZE * sizeof(uint32_t));

    // Initialize indices with random permutation (Fisher-Yates shuffle)
    for (size_t i = 0; i < SIZE; i++) {
        h_indices[i] = i;
    }

    // LCG parameters for shuffle
    uint32_t seed = 12345;
    for (size_t i = SIZE - 1; i > 0; i--) {
        seed = 1664525 * seed + 1013904223;
        size_t j = seed % (i + 1);

        uint32_t temp = h_indices[i];
        h_indices[i] = h_indices[j];
        h_indices[j] = temp;
    }

    // Copy indices to device
    cudaMemcpy(d_indices, h_indices, SIZE * sizeof(uint32_t), cudaMemcpyHostToDevice);

    // Run baseline measurement
    measure_baseline<<<1, 1>>>(d_baseline);
    cudaDeviceSynchronize();

    uint64_t baseline_cycles;
    cudaMemcpy(&baseline_cycles, d_baseline, sizeof(uint64_t), cudaMemcpyDeviceToHost);

    // Run 3 trials of DRAM latency measurement
    uint64_t results[3];
    for (int trial = 0; trial < 3; trial++) {
        measure_dram_latency<<<1, 1>>>(d_indices, d_cycles, SIZE);
        cudaDeviceSynchronize();

        uint64_t cycles;
        cudaMemcpy(&cycles, d_cycles, sizeof(uint64_t), cudaMemcpyDeviceToHost);

        // Subtract baseline overhead
        results[trial] = cycles > baseline_cycles ? cycles - baseline_cycles : cycles;
    }

    // Sort and get median
    std::sort(results, results + 3);
    uint64_t median_latency = results[1];

    printf("dram_latency_cycles: %lu\n", median_latency);

    // Cleanup
    free(h_indices);
    cudaFree(d_indices);
    cudaFree(d_cycles);
    cudaFree(d_baseline);

    return 0;
}

#include <cuda_runtime.h>
#include <cstdio>
#include <cstdint>
#include <cstddef>
#include <cstdlib>
#include <algorithm>
#include <cstring>

#define MAX_SIZE_MB 16
#define MIN_SIZE_MB 1
#define STEP_MB 0.5
#define TRIALS 3
#define ITERATIONS 10000000

__global__ void measure_latency(volatile uint32_t* data, uint64_t* cycles, size_t size) {
    if (threadIdx.x != 0 || blockIdx.x != 0) return;

    uint32_t idx = 0;
    asm volatile("" : : : "memory");
    volatile uint64_t start = clock64();

    #pragma unroll 1
    for (uint64_t i = 0; i < ITERATIONS; i++) {
        idx = data[idx % size];
    }

    volatile uint64_t end = clock64();
    asm volatile("" : : : "memory");

    volatile uint64_t sink64 = (uint64_t)idx;
    asm volatile("" : "+l"(sink64) : : "memory");

    *cycles = (end - start) / ITERATIONS;
}

void build_random_permutation(uint32_t* indices, size_t size) {
    // Initialize with sequential indices
    for (size_t i = 0; i < size; i++) {
        indices[i] = i;
    }

    // Fisher-Yates shuffle with LCG
    uint32_t seed = 12345;
    for (size_t i = size - 1; i > 0; i--) {
        seed = seed * 1664525 + 1013904223;
        uint32_t j = seed % (i + 1);
        uint32_t temp = indices[i];
        indices[i] = indices[j];
        indices[j] = temp;
    }
}

int main() {
    // Allocate maximum working set
    size_t max_elements = (MAX_SIZE_MB * 1024 * 1024) / sizeof(uint32_t);
    uint32_t* h_indices = (uint32_t*)malloc(max_elements * sizeof(uint32_t));
    uint32_t* d_indices;
    uint64_t* d_cycles;
    uint64_t h_cycles;

    cudaMalloc(&d_indices, max_elements * sizeof(uint32_t));
    cudaMalloc(&d_cycles, sizeof(uint64_t));

    // Build random permutation
    build_random_permutation(h_indices, max_elements);
    cudaMemcpy(d_indices, h_indices, max_elements * sizeof(uint32_t), cudaMemcpyHostToDevice);

    double best_transition_size = 0.0;
    double max_latency_jump = 0.0;

    // Sweep working set sizes
    for (double size_mb = MIN_SIZE_MB; size_mb <= MAX_SIZE_MB; size_mb += STEP_MB) {
        size_t size_elements = (size_mb * 1024 * 1024) / sizeof(uint32_t);

        // Run multiple trials
        uint64_t trial_cycles[TRIALS];
        for (int trial = 0; trial < TRIALS; trial++) {
            measure_latency<<<1, 1>>>(d_indices, d_cycles, size_elements);
            cudaDeviceSynchronize();
            cudaMemcpy(&h_cycles, d_cycles, sizeof(uint64_t), cudaMemcpyDeviceToHost);
            trial_cycles[trial] = h_cycles;
        }

        // Calculate median
        std::sort(trial_cycles, trial_cycles + TRIALS);
        uint64_t median_cycles = trial_cycles[TRIALS / 2];

        printf("size_mb: %.1f cycles: %lu\n", size_mb, median_cycles);
    }

    cudaFree(d_indices);
    cudaFree(d_cycles);
    free(h_indices);

    return 0;
}
